// ── Helper: generate dates spread across 3 weeks of weekdays ──

function generateDates(count: number): string[] {
  // Start from 3 weeks ago
  const start = new Date();
  start.setDate(start.getDate() - 21);
  start.setHours(8, 0, 0, 0);

  const weekdays: Date[] = [];
  const d = new Date(start);
  while (weekdays.length < 15) {
    if (d.getDay() >= 1 && d.getDay() <= 5) {
      weekdays.push(new Date(d));
    }
    d.setDate(d.getDate() + 1);
  }

  const dates: string[] = [];
  for (let i = 0; i < count; i++) {
    const day = weekdays[i % weekdays.length];
    const hours = 8 + Math.floor(Math.random() * 9); // 8-16
    const mins = Math.floor(Math.random() * 60);
    const date = new Date(day);
    date.setHours(hours, mins, Math.floor(Math.random() * 60), 0);
    dates.push(date.toISOString());
  }

  return dates.sort();
}

